# ---------------------------------------------------------------------------
# Win32-API-Helfer fuer korrekte Taskleisten-Integration
# ---------------------------------------------------------------------------
# Hintergrund:
#   overrideredirect(True) entfernt den Windows-Rahmen, loescht aber auch
#   WS_EX_APPWINDOW aus den Extended Window Styles. Ohne dieses Flag zeigt
#   Windows keine Taskleisten-Vorschau und bringt das Fenster beim Klick
#   auf den Taskleisteneintrag nicht in den Vordergrund.
#
# Loesung:
#   Nach dem Erstellen des Fensters wird WS_EX_APPWINDOW via SetWindowLongW
#   explizit gesetzt. Zusaetzlich wird SetForegroundWindow verwendet, um
#   das Fenster beim Taskleisten-Klick korrekt zu aktivieren.
# ---------------------------------------------------------------------------

if sys.platform == "win32":
    import ctypes  # noqa: F811

    _user32   = ctypes.windll.user32
    _dwmapi   = ctypes.windll.dwmapi

    GWL_EXSTYLE        = -20
    WS_EX_APPWINDOW    = 0x00040000
    WS_EX_TOOLWINDOW   = 0x00000080
    WS_EX_NOACTIVATE   = 0x08000000
    SW_MINIMIZE        = 6
    SW_RESTORE         = 9

    def _get_hwnd(tk_widget) -> int:
        """Gibt das Win32-HWND fuer ein Tk-Widget zurueck."""
        return _user32.GetParent(tk_widget.winfo_id()) or tk_widget.winfo_id()

    def _apply_appwindow_style(tk_widget) -> None:
        """Setzt WS_EX_APPWINDOW und entfernt WS_EX_TOOLWINDOW.

        Muss nach overrideredirect(True) und nach dem ersten update_idletasks()
        aufgerufen werden, damit Windows das Fenster korrekt in der Taskleiste
        registriert und die DWM-Vorschau aktiviert.
        """
        try:
            hwnd = _get_hwnd(tk_widget)
            ex_style = _user32.GetWindowLongW(hwnd, GWL_EXSTYLE)
            # WS_EX_TOOLWINDOW entfernen (verhindert Taskleisteneintrag)
            ex_style &= ~WS_EX_TOOLWINDOW
            # WS_EX_APPWINDOW setzen (erzwingt Taskleisteneintrag + DWM-Vorschau)
            ex_style |= WS_EX_APPWINDOW
            _user32.SetWindowLongW(hwnd, GWL_EXSTYLE, ex_style)
            # Fenster kurz verstecken und wieder anzeigen damit Windows
            # den neuen Style sofort uebernimmt
            _user32.SetWindowPos(
                hwnd, 0, 0, 0, 0, 0,
                0x0001 | 0x0002 | 0x0004 | 0x0010 | 0x0020  # SWP_NOMOVE|NOSIZE|NOZORDER|NOACTIVATE|FRAMECHANGED
            )
        except Exception as exc:
            logger.debug("Win32 SetWindowPos fehlgeschlagen (nicht-Windows): %s", exc)

    def _bring_to_front(tk_widget) -> None:
        """Bringt das Fenster in den Vordergrund (umgeht Windows-Fokus-Schutz)."""
        try:
            hwnd = _get_hwnd(tk_widget)
            # AllowSetForegroundWindow + SetForegroundWindow
            _user32.AllowSetForegroundWindow(0xFFFFFFFF)
            _user32.ShowWindow(hwnd, SW_RESTORE)
            _user32.SetForegroundWindow(hwnd)
            _user32.BringWindowToTop(hwnd)
        except Exception as exc:
            logger.debug("Win32 SetForegroundWindow fehlgeschlagen (nicht-Windows): %s", exc)
else:
    def _apply_appwindow_style(tk_widget) -> None:  # type: ignore[misc]
        pass

    def _bring_to_front(tk_widget) -> None:  # type: ignore[misc]
        pass

_EMBEDDED = ""

def parse_sfo(data: bytes) -> dict[str, object]:
    """Parst eine param.sfo-Datei und extrahiert Metadaten.

    Args:
        data: Rohe Bytes der .sfo-Datei.

    Returns:
        Dictionary mit Schl├╝ssel-Wert-Paaren aus der SFO-Datei,
        oder ein leeres Dictionary bei Fehler.
    """
    try:
        if data[:4] != b'\x00PSF':
            return {}

        header = struct.unpack('<IIII', data[4:20])
        key_ptr: int = header[0]
        data_ptr: int = header[1]
        count: int = header[2]

        entries = []
        for i in range(count):
            entry = struct.unpack('<HHIII', data[20 + i * 16: 20 + (i + 1) * 16])
            entries.append(entry)

        results: dict[str, object] = {}
        for key_off, data_fmt, data_len, _data_max, data_off in entries:
            k_start = key_ptr + key_off
            k_end = data.find(b'\x00', k_start)
            key = data[k_start:k_end].decode('utf-8')

            v_start = data_ptr + data_off
            if data_fmt == 0x0204:   # UTF-8-String
                v_end = data.find(b'\x00', v_start)
                value: object = data[v_start:v_end].decode('utf-8')
            elif data_fmt == 0x0004:  # 32-Bit-Integer
                value = struct.unpack('<I', data[v_start:v_start + 4])[0]
            else:
                value = data[v_start:v_start + data_len]

            results[key] = value

        return results

    except struct.error as exc:
        logger.warning("SFO-Parsing fehlgeschlagen (Strukturfehler): %s", exc)
        return {}
    except UnicodeDecodeError as exc:
        logger.warning("SFO-Parsing fehlgeschlagen (Dekodierungsfehler): %s", exc)
        return {}
    except Exception as exc:  # noqa: BLE001
        logger.warning("SFO-Parsing fehlgeschlagen (Unerwarteter Fehler): %s", exc)
        return {}

# ---------------------------------------------------------------------------
# ProgressEngine: Robuste, gewichtete Fortschrittsanzeige f├╝r 5 Aufgaben
# ---------------------------------------------------------------------------

class ProgressEngine:
    """Verwaltet den Gesamtfortschritt f├╝r alle 5 Konvertierungs-Aufgaben.

    Prinzipien:
    - Jede der 5 Aufgaben bekommt exakt 20 % des Gesamtbalkens.
    - Jede Aufgabe ist intern in 3 Phasen unterteilt:
        Vorbereitung  5 %  (Scan, Validierung, Mount-Warten)
        Payload      90 %  (Byte-basiert: echte Bytes / Dateianzahl)
        Validierung   5 %  (Hash-Check, Dismount, Abschluss)
    - Safety-Plateau bei 95 %: Die UI zeigt niemals 100 % w├ñhrend der
      letzte Flush/Commit noch laeuft. Nur _finish_success() darf 100 % setzen.
    - Fortschritt ist strikt monoton steigend (niemals r├╝ckw├ñrts).
    - Status-Feedback: z.B. "Aufgabe 5/8: Modifiziere Dateisystem... [32/50 Dateien]"
        - ETA-Anzeige: wird nur angezeigt, wenn die Sch├ñtzung ausreichend
            stabil ist (genug Fortschritt + genug Laufzeit).
    - Transaktions-Logik: Fortschritt wird erst nach Bestaetigung des
      Dateisystem-Commits auf 100 % gesetzt.
    """

    # Gewichtung: 8 Aufgaben x 12.5 % = 100 %
    TASK_WEIGHT      = 100.0 / 8  # % pro Aufgabe (12.5 %)
    NUM_TASKS        = 8

    # Phasen-Anteile innerhalb einer Aufgabe (Summe = 100 %)
    PHASE_PREPARE    = 0.05   # 5 % Vorbereitung
    PHASE_PAYLOAD    = 0.90   # 90 % Datenverarbeitung
    PHASE_VALIDATE   = 0.05   # 5 % Validierung/Abschluss

    # Safety-Limit: niemals 100 % w├ñhrend Commit laeuft
    SAFETY_LIMIT     = 95.0

    # Interpolations-Konstanten (Easing)
    EASING_FACTOR    = 0.30   # Exponentielles Easing
    CATCHUP_PER_POLL = 2.0    # %/Poll lineares Aufholen

    def __init__(self) -> None:
        """Initialisiert die ProgressEngine im Ruhezustand."""
        self._task_idx: int = 0          # 0-basiert (0ÔÇô5)
        self._phase: str = "idle"        # idle | prepare | payload | validate | done
        self._payload_done: float = 0.0  # Verarbeitete Einheiten (Bytes oder Dateien)
        self._payload_total: float = 0.0 # Gesamte Einheiten
        self._status_text: str = ""      # Status-Text f├╝r die GUI
        self._committed: bool = False    # True nach Dateisystem-Commit bestaetigt
        self._raw_progress: float = 0.0  # Interner Rohwert (0ÔÇô100)
        self._displayed: float = 0.0     # Angezeigter Wert (Easing)
        self._task_t0: float = time.monotonic()
        self._payload_t0: float = self._task_t0
        self._eta_seconds: float | None = None
        self._external_eta_seconds: float | None = None
        self._external_progress_active: bool = False

    # ------------------------------------------------------------------
    # Oeffentliche API
    # ------------------------------------------------------------------

    def start_task(self, task_idx: int, task_name: str) -> None:
        """Startet eine neue Aufgabe (0-basiert).

        Args:
            task_idx:  Index der Aufgabe (0 = Aufgabe 1, 7 = Aufgabe 8).
            task_name: Anzeigename f├╝r das Status-Feedback.
        """
        self._task_idx = max(0, min(task_idx, self.NUM_TASKS - 1))
        task_start = self._task_idx * self.TASK_WEIGHT
        self._phase = "prepare"
        self._payload_done = 0.0
        self._payload_total = 0.0
        self._committed = False
        self._task_t0 = time.monotonic()
        self._payload_t0 = self._task_t0
        self._eta_seconds = None
        self._external_eta_seconds = None
        self._external_progress_active = False
        self._status_text = f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: {task_name}"
        # Neuer Task muss einen alten Lauf hart ueberschreiben.
        # Sonst kann ein Resume-/Abbruch-Restwert (z. B. 93%) in den
        # naechsten Task hineinragen und ETA/Status verfaelschen.
        self._raw_progress = task_start
        self._displayed = task_start

    def begin_prepare(self, description: str = "Vorbereitung...") -> None:
        """Beginnt die Vorbereitungs-Phase (5 %).

        Args:
            description: Kurze Beschreibung fuer das Status-Feedback.
        """
        self._phase = "prepare"
        self._status_text = (
            f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: {description}"
        )
        target = self._task_start() + self.TASK_WEIGHT * self.PHASE_PREPARE
        self._advance_raw(target)

    def begin_payload(
        self,
        total_units: float,
        description: str = "Verarbeite...",
        unit_label: str = "Bytes",
    ) -> None:
        """Beginnt die Payload-Phase (90 %) mit Byte-/Datei-basiertem Fortschritt."""
        self._phase = "payload"
        self._payload_done = 0.0
        self._payload_total = max(1.0, total_units)
        self._payload_t0 = time.monotonic()
        self._unit_label = unit_label
        self._payload_desc = description
        self._status_text = (
            f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: {description} "
            f"[0/{self._fmt_units(self._payload_total, unit_label)}]"
        )
        target = self._task_start() + self.TASK_WEIGHT * self.PHASE_PREPARE
        self._advance_raw(target)

    def update_payload(self, done_units: float) -> None:
        """Aktualisiert den Payload-Fortschritt (Byte-basiert)."""
        if self._phase != "payload":
            return
        self._payload_done = min(done_units, self._payload_total)
        frac = self._payload_done / self._payload_total
        payload_start = self._task_start() + self.TASK_WEIGHT * self.PHASE_PREPARE
        payload_end = self._task_start() + self.TASK_WEIGHT * (self.PHASE_PREPARE + self.PHASE_PAYLOAD)
        safe_end = payload_start + (payload_end - payload_start) * 0.95
        target = payload_start + frac * (safe_end - payload_start)
        self._advance_raw(target)
        label = getattr(self, "_unit_label", "Einheiten")
        desc = getattr(self, "_payload_desc", "Verarbeite...")
        self._status_text = (
            f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: {desc} "
            f"[{self._fmt_units(self._payload_done, label)}/{self._fmt_units(self._payload_total, label)}]"
        )

    def begin_validate(self, description: str = "Validierung...") -> None:
        """Beginnt die Validierungs-Phase (5 %)."""
        self._phase = "validate"
        self._status_text = (
            f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: {description}"
        )
        payload_end = self._task_start() + self.TASK_WEIGHT * (self.PHASE_PREPARE + self.PHASE_PAYLOAD)
        self._advance_raw(payload_end)

    def commit_task(self) -> None:
        """Bestaetigt den Dateisystem-Commit und hebt das Safety-Plateau auf."""
        self._committed = True
        self._phase = "done"
        task_end = self._task_start() + self.TASK_WEIGHT
        safe_global = min(task_end, self.SAFETY_LIMIT)
        self._advance_raw(safe_global)
        self._status_text = (
            f"Aufgabe {self._task_idx + 1}/{self.NUM_TASKS}: Abgeschlossen."
        )

    def finish_task(self) -> None:
        """Schliesst die aktuelle Aufgabe ab (Alias fuer commit_task)."""
        self.commit_task()

    def finish_all(self) -> None:
        """Setzt den Fortschritt auf 100 % (nur nach vollstaendigem Abschluss)."""
        self._raw_progress = 100.0
        self._displayed = 100.0
        self._phase = "done"
        self._status_text = "Abgeschlossen."

    def update_external_progress(self, progress_pct: float) -> None:
        """Synchronisiert extern gemessenen Fortschritt (0-100) in die Engine."""
        self._external_progress_active = True
        self._advance_raw(progress_pct)

    def set_external_eta_seconds(self, eta_seconds: float | None) -> None:
        """Setzt eine belastbare Live-ETA aus exakten Laufzeitmetriken."""
        if eta_seconds is None or eta_seconds < 0.0 or eta_seconds > 24 * 3600:
            self._external_eta_seconds = None
        else:
            self._external_eta_seconds = float(eta_seconds)

    def tick(self) -> tuple[float, str]:
        """Berechnet den naechsten Anzeige-Fortschritt via Easing.

        Muss alle PROGRESS_POLL_MS ms aufgerufen werden (aus _update_progress_gui).

        Returns:
            Tupel (displayed_pct, status_text) f├╝r die GUI-Aktualisierung.
        """
        target = self._raw_progress
        disp   = self._displayed
        if target > disp:
            gap = target - disp
            if gap > 0.05:
                eased  = disp + gap * self.EASING_FACTOR
                linear = disp + min(self.CATCHUP_PER_POLL, gap)
                disp   = max(eased, linear)
            else:
                disp = target
            disp = min(disp, target)
        # Niemals 100 % via tick() ÔÇô nur finish_all() darf das
        self._displayed = max(self._displayed, min(disp, 99.9))
        return self._displayed, self._status_with_eta(self._status_text)

    @property
    def raw_progress(self) -> float:
        """Aktueller Rohwert (0ÔÇô100), ohne Easing."""
        return self._raw_progress

    @property
    def status(self) -> str:
        """Aktueller Status-Text."""
        return self._status_text

    # ------------------------------------------------------------------
    # Hilfsmethoden
    # ------------------------------------------------------------------

    def _task_start(self) -> float:
        """Gibt den Fortschritts-Startwert der aktuellen Aufgabe zur├╝ck."""
        return self._task_idx * self.TASK_WEIGHT

    def _advance_raw(self, target: float) -> None:
        """Setzt den Rohwert vorw├ñrts (niemals zur├╝ck)."""
        self._raw_progress = max(self._raw_progress, min(target, 99.9))

    def _status_with_eta(self, base: str) -> str:
        """Erweitert den Statustext um ETA, wenn die Sch├ñtzung stabil ist."""
        eta_s = self._external_eta_seconds
        if eta_s is None:
            return base
        return f"{base} | ETA ~{self._fmt_eta(eta_s)}"

    def _estimate_eta_seconds(self) -> float | None:
        """Sch├ñtzt verbleibende Zeit innerhalb der aktuellen Aufgabe.

        Die ETA wird erst freigegeben, wenn genug Daten vorliegen:
        - Aufgabe l├ñuft (nicht idle/done)
        - mindestens 8 Sekunden Laufzeit
        - mindestens 18% Fortschritt innerhalb der aktuellen Aufgabe
        """
        if self._phase in ("idle", "done"):
            return None

        if self._external_progress_active:
            return None

        elapsed = time.monotonic() - self._task_t0
        if elapsed < 8.0:
            return None

        task_start = self._task_start()
        task_frac = (self._raw_progress - task_start) / self.TASK_WEIGHT
        task_frac = max(0.0, min(task_frac, 1.0))
        if task_frac < 0.18:
            return None

        remaining = 1.0 - task_frac
        if remaining <= 0.0:
            return 0.0

        # Grundsch├ñtzung via lineare Extrapolation der bisherigen Task-Laufzeit.
        eta_now = elapsed * (remaining / max(task_frac, 1e-6))
        if eta_now < 0.0 or eta_now > 24 * 3600:
            return None

        # Glaetten gegen Spruenge, damit ETA nicht flackert.
        if self._eta_seconds is None:
            self._eta_seconds = eta_now
        else:
            self._eta_seconds = self._eta_seconds * 0.70 + eta_now * 0.30
        return self._eta_seconds

    @staticmethod
    def _fmt_eta(seconds: float) -> str:
        """Formatiert ETA konsequent als mm:ss (Gesamtminuten:Sekunden)."""
        total = max(0, int(round(seconds)))
        m = total // 60
        s = total % 60
        return f"{m:02d}:{s:02d}"

    @staticmethod
    def _fmt_units(value: float, unit_label: str) -> str:
        """Formatiert Einheiten lesbar (Bytes oder Dateien)."""
        if unit_label.lower() in ("bytes", "byte", "b"):
            for unit in ("B", "KB", "MB", "GB", "TB"):
                if value < 1024.0:
                    return f"{value:.1f} {unit}"
                value /= 1024.0
            return f"{value:.1f} PB"
        return f"{int(value)} {unit_label}"

